INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (1, N'Consulta 1', N'SELECT [PkEquipo]
      ,[Id]
      ,[Nombre]
      ,[IdBD]
      ,[Linea]
      ,[IdLinea]
      ,[Nivel]
      ,[IdNivel]
      ,[Clase]
      ,[IdClase]
      ,[Descripcion]
      ,[Zona]
      ,[Orden]
      ,[FecHorActOrden]
      ,[Estado]
  FROM [dbo].[Maquinas]')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (2, N'Consulta 2', N'

SELECT [ID_INCIDENCIA]
      ,[USUARIO]
      ,[PANTALLA]
      ,[DESCRIPCION]
      ,[APLICACION]
  FROM [dbo].[INCIDENCIAS]
')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (3, N'Consulta 3', N'Select isnull(CausaNombre,''Causa no definida'') as ''Causa_paro'', count(*) as ''Número_de_paros'',
replace(convert(numeric(9,2), (sum(duracion)+sum(isnull(DuracionBajaVelocidad,0)))/60000),''.'','','')  as ''Total_minutos_paradas'',
replace(convert(numeric(9,2), (sum(duracion)+sum(isnull(DuracionBajaVelocidad,0)))/3600000),''.'','','') as ''Total_horas_paradas''
from dbo.ParosPerdidas
[WHEREPERDIDA]
group by Causanombre
order by Causanombre asc')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (4, N'Análisis de paros por causa', N'Select isnull(CausaNombre,''Causa no definida'') as ''Causa_paro'', count(*) as ''Número_de_paros'',
replace(convert(numeric(9,2), (sum(DuracionParoMayor)+sum(DuracionParosMenores)+sum(isnull(DuracionBajaVelocidad,0)))/60000),''.'','','')  as ''Total_minutos_paradas'',
replace(convert(numeric(9,2), (sum(DuracionParoMayor)+sum(DuracionParosMenores)+sum(isnull(DuracionBajaVelocidad,0)))/3600000),''.'','','') as ''Total_horas_paradas''
from dbo.ParosPerdidas PP
INNER JOIN Lineas L ON PP.IdLinea = L.NumeroLinea
[WHEREPERDIDA]
group by Causanombre
order by Causanombre asc')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (5, N'Envases producidos por turno', N'Select T.Linea AS ''Numero_de_tren'', convert(varchar(100),convert(date, T.Fecha)) + '' '' + T.Turno as ''Turno'',
sum(ENVASES_LLENADORA) as ''Envases_llenadora'', sum(ENVASES_PALETIZADORA) as ''Envases_paletizadora'',
sum(ENVASES_RECHAZADOS) as ''Envases_rechazados'', Format(Avg(OEE), ''N'',''es-ES'') as ''Rendimiento'', convert(numeric(18,2),PTC.TIEMPO_PLANIFICADO) as ''Tiempo_planificado'',
convert(numeric(18,2),PTC.TIEMPO_OPERATIVO) as ''Tiempo_Operativo'', convert(numeric(18,2),ptc.TIEMPO_NETO) as ''Tiempo_Neto''
FROM [dbo].[ProduccionTurnosConsolidada] PTC
[WHEREPTC]
INNER JOIN [dbo].[Turnos] T ON PTC.TURNO = T.Id
GROUP BY convert(varchar(100),convert(date, T.Fecha)) + '' '' + T.Turno, T.Linea, PTC.TIEMPO_PLANIFICADO, PTC.TIEMPO_OPERATIVO, ptc.TIEMPO_NETO
ORDER BY convert(varchar(100),convert(date, T.Fecha)) + '' '' + T.Turno, T.LINEA ASC
')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (6, N'Envases producidos por línea', N'Select T.Linea AS ''Numero_linea'', count(*) as ''Numero_turnos'', sum(ENVASES_LLENADORA) as ''Envases_llenadora'', 
sum(ENVASES_PALETIZADORA) as ''Envases_paletizadora'',
sum(ENVASES_RECHAZADOS) as ''Envases_rechazados''
FROM [dbo].[ProduccionTurnosConsolidada] PTC
INNER JOIN [dbo].[Turnos] T ON PTC.TURNO = T.Id
[WHEREPTC]
GROUP BY T.Linea
ORDER BY T.LINEA ASC')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (7, N'Máquinas con más paros menores propios', N'Select M.Nombre as Maquina, count(*) as ''Número_de_paros'',
replace(convert(numeric(9,2), (sum(DuracionParosMenores)+sum(isnull(DuracionBajaVelocidad,0)))/60),''.'','','')  as ''Total_minutos_paradas'',
replace(convert(numeric(9,2), (sum(DuracionParosMenores)+sum(isnull(DuracionBajaVelocidad,0)))/3600),''.'','','') as ''Total_horas_paradas''
from dbo.ParosPerdidas PP
INNER JOIN [dbo].[Maquinas] M ON M.Id = PP.EquipoId
where PP.IdTipoParoPerdida=2 [ANDPERDIDA]
group by M.Nombre
order by M.Nombre asc')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (8, N'Media de arranques de línea', N'SELECT ''Linea '' + convert(varchar(100),Linea) + '' - '' + DescripcionLinea as Linea,
case 
when TipoArranque=1 then ''Arranque Lunes''
else ''Arranque 2 turnos''
end as TipoArranque
, isnull(MinutosFinal1,0) as Minutos
FROM [MES_MSM].[dbo].[OrdenesArranque]
[WHEREARRANQUE]')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (9, N'Media de cambios de producto', N'HECHO')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (10, N'Media de arranques de linea', N'HECHO')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (11, N'Media de cambios de linea', N'HECHO')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (12, N'Observaciones', N'SELECT DISTINCT IdLinea AS Linea, T.Turno, MaquinaCausaId  as ''Codigo_Maquina_Causante'', MaquinaCausaNombre AS ''Maquina_Causante'', 
EquipoConstructivoId AS ''Codigo_Equipo_constructivo_responsable'', EquipoConstructivoNombre AS ''Equipo_constructivo_responsable'', Observaciones, 
0 as ''Cuenta_Equipo_Constructivo''
FROM DBO.ParosPerdidas PP
INNER JOIN DBO.Turnos T ON PP.IdTipoTurno = T.IdTipoTurno
WHERE PP.Observaciones IS NOT NULL AND PP.Observaciones<>'''' [ANDPERDIDA]')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (13, N'Índices de Líneas entre fechas', N'SELECT IdLinea AS Linea, MaquinaCausaId AS ''Codigo_Maquina_Causante'', MaquinaCausaNombre as ''Maquina_Causante'',
case 
when IdTipoParoPerdida= 1 then ''Paro Mayor''
when IdTipoParoPerdida=2 and DuracionBajaVelocidad=0 then ''Paro menor''
else ''Baja Velocidad'' end as ''Cateogia_paro'',
count(*) as ''Numero_paros'',
replace(convert(numeric(9,2), (sum(DuracionParoMayor)+sum(DuracionParosMenores)+sum(isnull(DuracionBajaVelocidad,0)))/60),''.'','','')  as ''Tiempo_total_minutos''
FROM DBO.ParosPerdidas
[WHEREPERDIDA]
group by IdTipoParoPerdida, DuracionBajaVelocidad, IdLinea, MaquinaCausaId, MaquinaCausaNombre')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (14, N'Paros agrupados por motivo', N'
SELECT IdLinea AS Linea, MaquinaCausaId AS ''Codigo_Maquina_Causante'', MaquinaCausaNombre as ''Maquina_Causante'',
count(*) as ''Numero_paros'',
replace(convert(numeric(9,2), (sum(duracion)+sum(isnull(DuracionBajaVelocidad,0)))/60000),''.'','','')  as ''Tiempo_total_minutos'',
Descripcion as ''Descripcion_averia''
FROM DBO.ParosPerdidas
[WHEREPERDIDA]
group by IdLinea, MaquinaCausaId, MaquinaCausaNombre, Descripcion')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (15, N'Paros agrupados por motivo y causa', N'Select MaquinaCausaId AS ''Codigo_Maquina_Causante'', MaquinaCausaNombre as ''Maquina_Causante'',
ISNULL(EquipoConstructivoId,''Sin Equipo definido'') AS ''Codigo_Equipo_constructivo_responsable'', EquipoConstructivoNombre AS ''Equipo_constructivo_responsable'',
isnull(CausaNombre,''Causa no definida'') as ''Causa_paro'', count(*) as ''Número_de_paros'',
replace(convert(numeric(9,2), (sum(duracion)+sum(isnull(DuracionBajaVelocidad,0)))/60000),''.'','','')  as ''Total_minutos_paradas'',
replace(convert(numeric(9,2), (sum(duracion)+sum(isnull(DuracionBajaVelocidad,0)))/3600000),''.'','','') as ''Total_horas_paradas''
from dbo.ParosPerdidas
[WHEREPERDIDA]
group by EquipoConstructivoId, EquipoConstructivoNombre, MaquinaCausaId, MaquinaCausaNombre, CausaNombre
order by EquipoConstructivoId asc')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (16, N'Paros provocados por equipos constructivos', N'Select IdLinea AS ''Linea'', PP.NombreTipoTurno, MotivoNombre as ''Motivo'', 
replace(convert(numeric(18,2), (sum(duracion))/60000),''.'','','')  as ''Duracion_Minutos'',
isnull(CausaNombre,''Causa no definida'') as ''Causa_paro'',
MaquinaCausaId AS ''Codigo_Maquina_Causante'', MaquinaCausaNombre as ''Maquina_Causante'',
ISNULL(EquipoConstructivoId,''Sin Equipo definido'') AS ''Codigo_Equipo_constructivo_responsable'', EquipoConstructivoNombre AS ''Equipo_constructivo_responsable'',
Descripcion, Observaciones
from dbo.ParosPerdidas PP
where Justificado =0 [ANDPERDIDA]
group by IdLinea,  PP.NombreTipoTurno, MotivoNombre, CausaNombre, EquipoConstructivoId, EquipoConstructivoNombre,MaquinaCausaNombre,
MaquinaCausaId,Descripcion, Observaciones')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (17, N'Paros sin justificar', N'Select Sum([Paros_Totales]) as ''Paros_Totales'',Sum([Paros_Justificados]) as ''Paros_Justificados''
,Sum([Paros_No_Justificados]) as ''Paros_No_Justificados'' 
From (
select count(*) as ''Paros_Totales'',0 as ''Paros_Justificados'',0 as ''Paros_No_Justificados'' 
from ParosPerdidas
[WHEREPERDIDA]
union all
Select 0,count(*),0
from ParosPerdidas
where Justificado=1 [ANDPERDIDA]
union all
Select 0,0, count(*)
from ParosPerdidas
where Justificado=0 [ANDPERDIDA]) t')
INSERT [dbo].[QUERIES] ([ID_QUERY], [NOMBRE], [TEXTO]) VALUES (18, N'Porcentaje de paros justificados', N'SELECT DISTINCT IdLinea AS Linea, T.Turno, MaquinaCausaId  as ''Codigo_Maquina_Causante'', MaquinaCausaNombre AS ''Maquina_Causante'', 
EquipoConstructivoId AS ''Codigo_Equipo_constructivo_responsable'', EquipoConstructivoNombre AS ''Equipo_constructivo_responsable'', 
Descripcion, 
replace(convert(numeric(9,2), (sum(duracion))/60000),''.'','','')  as ''Duracion_parada''
FROM DBO.ParosPerdidas PP
INNER JOIN DBO.Turnos T ON PP.IdTipoTurno = T.IdTipoTurno
WHERE PP.Observaciones IS NOT NULL AND PP.Observaciones<>'''' --[ANDPERDIDA]
group by T.Turno, MaquinaCausaId, IdLinea, MaquinaCausaNombre, EquipoConstructivoId, EquipoConstructivoNombre, Descripcion')
